#include <stdio.h>
#include <string.h>

/* == EXEMPLE ================================================
 * Tableau de pointeurs vers int et tri par selection
 * On echange les pointeurs, pas les valeurs pointees.
 * =========================================================== */
void example_sort_ptrs(int *arr[], int n) {
    for (int i = 0; i < n - 1; i++) {
        int min_idx = i;
        for (int j = i + 1; j < n; j++) {
            if (*arr[j] < *arr[min_idx]) min_idx = j;
        }
        int *tmp = arr[i]; arr[i] = arr[min_idx]; arr[min_idx] = tmp;
    }
}
void example_demo(void) {
    int a = 30, b = 10, c = 20;
    int *ptrs[] = {&a, &b, &c};
    example_sort_ptrs(ptrs, 3);
    for (int i = 0; i < 3; i++) printf("%d ", *ptrs[i]);
    printf("\n");
}
